const ORGANIZATION_ID = 'REEMPLAZA_ORGANIZATION_ID';
const ASSIGNED_TO = 'Alejandro Torres';

const body = $json.body || $json;

function getValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== '') {
      return String(value).trim();
    }
  }
  return '';
}

function cleanPhone(phone) {
  if (!phone) return '';
  let cleaned = String(phone).replace(/[^0-9]/g, '');
  if (cleaned.length === 10 && (cleaned.startsWith('787') || cleaned.startsWith('939'))) {
    cleaned = '1' + cleaned;
  }
  return cleaned;
}

function parseMoney(value) {
  if (!value) return null;
  const cleaned = String(value).replace(/[^0-9.]/g, '');
  if (!cleaned) return null;
  return Number(cleaned);
}

const fullNameRaw = getValue(body.full_name, body.nombre_completo, body.name, body.nombre, body['Full Name'], body['Nombre completo']);
const firstName = getValue(body.first_name, body.firstname, body.nombre, body['First Name'], fullNameRaw.split(' ')[0]);
const lastName = getValue(body.last_name, body.lastname, body.apellido, body['Last Name'], fullNameRaw.split(' ').slice(1).join(' '));
const fullName = fullNameRaw || `${firstName} ${lastName}`.trim();

const phone = cleanPhone(getValue(body.phone, body.telefono, body.tel, body.mobile, body.celular, body['Phone Number'], body['Telefono']));
const email = getValue(body.email, body.correo, body['Email']);
const propertyCity = getValue(body.property_city, body.city, body.pueblo, body.municipio, body['Pueblo'], body['Municipio']);
const propertyAddress = getValue(body.property_address, body.address, body.direccion, body.direccion_propiedad, body['Direccion']);
const propertyCondition = getValue(body.property_condition, body.condition, body.condicion, body['Condicion']);
const occupiedStatus = getValue(body.occupied_status, body.ocupada, body.occupancy, body.ocupacion, body['Ocupacion']);
const sellingTimeline = getValue(body.selling_timeline, body.timeline, body.tiempo_para_vender, body.cuando_vende, body['Tiempo para vender'], body['Cuando desea vender']);
const sellerMotivation = getValue(body.seller_motivation, body.motivation, body.motivo, body.razon, body['Motivo de venta'], body['Motivacion']);
const askingPrice = parseMoney(getValue(body.asking_price, body.precio, body.cuanto_quiere, body.price, body['Precio deseado'], body['Cuanto desea recibir']));
const mortgageBalance = parseMoney(getValue(body.mortgage_balance, body.balance_hipoteca, body.deuda, body['Balance de hipoteca'], body['Deuda']));
const fbLeadId = getValue(body.fb_lead_id, body.leadgen_id, body.id, body['Lead ID'], body['Facebook Lead ID']);
const sourceCampaign = getValue(body.source_campaign, body.campaign_name, body.ad_name, body['Campaign Name'], body['Ad Name'], 'Facebook Instant Form');
const sourceForm = getValue(body.source_form, body.form_name, body['Form Name'], 'Meta Instant Form');

const text = `${propertyCondition} ${occupiedStatus} ${sellingTimeline} ${sellerMotivation}`.toLowerCase();
let leadScore = 0;
if (phone) leadScore += 20;
if (email) leadScore += 5;
if (propertyCity) leadScore += 10;
if (propertyAddress) leadScore += 15;
if (askingPrice !== null) leadScore += 10;
if (sellingTimeline) leadScore += 10;
if (sellerMotivation) leadScore += 10;
if (text.includes('urgente') || text.includes('rapido') || text.includes('ya') || text.includes('inmediato')) leadScore += 20;
if (text.includes('30') || text.includes('este mes') || text.includes('lo antes')) leadScore += 15;
if (text.includes('vac') || text.includes('desocup')) leadScore += 10;
if (text.includes('herencia') || text.includes('hered')) leadScore += 10;
if (text.includes('repar') || text.includes('dano') || text.includes('mal estado')) leadScore += 10;
if (text.includes('atras') || text.includes('foreclosure') || text.includes('ejecucion')) leadScore += 20;

let leadTemperature = 'Frio';
if (leadScore >= 75) leadTemperature = 'Caliente';
else if (leadScore >= 45) leadTemperature = 'Tibio';

const nextAction = leadTemperature === 'Caliente'
  ? 'Llamar inmediatamente y pedir detalles de la propiedad'
  : 'Contactar para calificar motivacion, precio y timeline';

const now = new Date();
const nextFollowUp = new Date(now.getTime() + 24 * 60 * 60 * 1000).toISOString();

return [
  {
    json: {
      organization_id: ORGANIZATION_ID,
      full_name: fullName,
      first_name: firstName,
      last_name: lastName,
      phone,
      email,
      source: 'Facebook Lead Ads via Zapier',
      source_campaign: sourceCampaign,
      source_form: sourceForm,
      fb_lead_id: fbLeadId,
      property_address: propertyAddress,
      property_city: propertyCity,
      property_condition: propertyCondition,
      occupied_status: occupiedStatus,
      selling_timeline: sellingTimeline,
      asking_price: askingPrice,
      mortgage_balance: mortgageBalance,
      seller_motivation: sellerMotivation,
      service_interest: 'Vender propiedad',
      stage: 'Nuevo Lead',
      lead_status: 'open',
      lead_temperature: leadTemperature,
      lead_score: leadScore,
      assigned_to: ASSIGNED_TO,
      conversation_summary: `Lead de Facebook. Pueblo: ${propertyCity || 'no indicado'}. Timeline: ${sellingTimeline || 'no indicado'}. Motivacion: ${sellerMotivation || 'no indicada'}. Condicion: ${propertyCondition || 'no indicada'}.`,
      next_action: nextAction,
      next_follow_up_at: nextFollowUp,
      raw_payload: body
    }
  }
];

const savedRaw = $json;
const savedLead = Array.isArray(savedRaw) ? savedRaw[0] : savedRaw;
const lead = $('Normalize + Score Facebook Lead').first().json;

return [
  {
    json: {
      organization_id: lead.organization_id,
      lead_id: savedLead.id,
      activity_type: 'lead_created',
      channel: 'Facebook Lead Ads via Zapier',
      direction: 'inbound',
      message: `Lead recibido desde Facebook Instant Form. Score: ${lead.lead_score}. Temperatura: ${lead.lead_temperature}. Accion: ${lead.next_action}`,
      metadata: {
        source_campaign: lead.source_campaign,
        source_form: lead.source_form,
        fb_lead_id: lead.fb_lead_id,
        phone: lead.phone
      },
      lead
    }
  }
];

const lead = $('Normalize + Score Facebook Lead').first().json;
const savedRaw = $('Save Lead in Supabase').first().json;
const savedLead = Array.isArray(savedRaw) ? savedRaw[0] : savedRaw;

const message = `NUEVO LEAD - LEADFLOW AI CRM

Fuente: Facebook Instant Form
Campana/Ad: ${lead.source_campaign || 'No indicado'}
Formulario: ${lead.source_form || 'No indicado'}

Nombre: ${lead.full_name || 'No indicado'}
Telefono: ${lead.phone || 'No indicado'}
Email: ${lead.email || 'No indicado'}

Pueblo: ${lead.property_city || 'No indicado'}
Direccion: ${lead.property_address || 'No indicada'}
Condicion: ${lead.property_condition || 'No indicada'}
Ocupacion: ${lead.occupied_status || 'No indicado'}

Quiere vender: ${lead.selling_timeline || 'No indicado'}
Precio deseado: ${lead.asking_price || 'No indicado'}
Balance hipoteca: ${lead.mortgage_balance || 'No indicado'}
Motivacion: ${lead.seller_motivation || 'No indicada'}

Score: ${lead.lead_score}/100
Temperatura: ${lead.lead_temperature}
Etapa: ${lead.stage}
Accion: ${lead.next_action}

CRM Lead ID: ${savedLead.id || 'No disponible'}`;

return [
  {
    json: {
      success: true,
      message,
      lead_id: savedLead.id,
      lead_name: lead.full_name,
      lead_phone: lead.phone
    }
  }
];
